sql:
SELECT status, COUNT(DISTINCT component_id) AS num_components, COUNT(DISTINCT manufacturer) AS num_manufacturers
FROM components
GROUP BY status;

SELECT COUNT(DISTINCT manufacturer) AS different_manufacturers,
       COUNT(component_id) AS total_components
FROM components;

SELECT component_name 
FROM components 
WHERE component_id NOT IN (SELECT component_id FROM parameters);
